### 3. 错误处理

```javascript
// 错误处理示例
try {
  const book = await fetchBookById(id);
  if (!book) {
    throw new Error('Book not found');
  }
  return book;
} catch (error) {
  console.error('Error fetching book:', error);
  throw error;
}
```

### 4. 数据验证

```javascript
// 数据验证示例
function validateBook(book) {
  const errors = [];

  if (!book.title || book.title.trim() === '') {
    errors.push('Title is required');
  }

  if (!book.author || book.author.trim() === '') {
    errors.push('Author is required');
  }

  if (book.publishedYear && (book.publishedYear < 1000 || book.publishedYear > new Date().getFullYear())) {
    errors.push('Invalid published year');
  }

  return {
    isValid: errors.length === 0,
    errors
  };
}
```

### 5. 业务逻辑

```javascript
// 业务逻辑示例
class BookService {
  async getAllBooks(filters = {}) {
    const query = this.buildQuery(filters);
    return this.repository.find(query);
  }

  async searchBooks(searchTerm) {
    return this.repository.search({
      $or: [
        { title: { $regex: searchTerm, $options: 'i' } },
        { author: { $regex: searchTerm, $options: 'i' } }
      ]
    });
  }

  buildQuery(filters) {
    const query = {};

    if (filters.author) {
      query.author = filters.author;
    }

    if (filters.genre) {
      query.genre = filters.genre;
    }

    if (filters.year) {
      query.publishedYear = filters.year;
    }

    return query;
  }
}
```

## 最佳实践

1. **单一职责**: 每个服务类应该只负责一种业务功能
2. **依赖注入**: 使用依赖注入来管理服务之间的依赖关系
3. **错误处理**: 统一处理错误，提供有意义的错误信息
4. **日志记录**: 记录关键操作，便于问题排查
5. **性能优化**: 使用缓存、批量操作等提高性能
6. **测试友好**: 设计可测试的代码，便于单元测试

## 总结

服务层是应用程序架构中的重要组成部分，它负责处理业务逻辑、协调数据访问和控制流程。通过合理设计服务层，可以提高代码的可维护性、可测试性和可扩展性。

